import{_ as o,o as a,c as t,ag as r}from"./chunks/framework.BB1Y0bZZ.js";const g=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"internals/changelog/GBIF.md","filePath":"internals/changelog/GBIF.md","lastUpdated":null}'),n={name:"internals/changelog/GBIF.md"};function i(l,e,s,d,c,h){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to this project will be documented in this file.</p><p>The format is based on <a href="https://keepachangelog.com/en/1.1.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>, and this project adheres to <a href="https://semver.org/spec/v2.0.0.html" target="_blank" rel="noreferrer">Semantic Versioning</a>.</p><h2 id="v1.2.0" tabindex="-1"><code>v1.2.0</code> <a class="header-anchor" href="#v1.2.0" aria-label="Permalink to &quot;`v1.2.0` {#v1.2.0}&quot;">​</a></h2><ul><li><p><strong>silenced</strong> the info messages for wrongly formatted dates in <code>_materialize</code></p></li><li><p><strong>added</strong> a <code>format</code> keyword to <code>localarchive</code> and <code>download</code> to return in different types</p></li><li><p><strong>added</strong> support to read from a local GBIF archive (h/t <a href="https://github.com/jeetsukumaran" target="_blank" rel="noreferrer">@jeetsukumaran</a>) <a href="https://github.com/PoisotLab/SpeciesDistributionToolkit.jl/issues/504" target="_blank" rel="noreferrer">#504</a></p></li><li><p><strong>changed</strong> the compat entry of <code>JSON</code> from <code>0.21</code> to <code>0.21, 1</code> [508]</p></li></ul><h2 id="v1.1.1" tabindex="-1"><code>v1.1.1</code> <a class="header-anchor" href="#v1.1.1" aria-label="Permalink to &quot;`v1.1.1` {#v1.1.1}&quot;">​</a></h2><ul><li><p><strong>fixed</strong> an issue where the delimiter was not properly infered by CSV <a href="https://github.com/PoisotLab/SpeciesDistributionToolkit.jl/issues/501" target="_blank" rel="noreferrer">#501</a></p></li><li><p><strong>added</strong> a <code>path</code> keyword to <code>GBIF.download</code> to store downloaded files in a specific path</p></li></ul><h2 id="v1.1.0" tabindex="-1"><code>v1.1.0</code> <a class="header-anchor" href="#v1.1.0" aria-label="Permalink to &quot;`v1.1.0` {#v1.1.0}&quot;">​</a></h2><ul><li><p><strong>added</strong> support for the download API <a href="https://github.com/PoisotLab/SpeciesDistributionToolkit.jl/issues/308" target="_blank" rel="noreferrer">#308</a></p></li><li><p><strong>added</strong> dependencies on CSV and ZipArchives</p></li></ul><h2 id="v1.0.2" tabindex="-1"><code>v1.0.2</code> <a class="header-anchor" href="#v1.0.2" aria-label="Permalink to &quot;`v1.0.2` {#v1.0.2}&quot;">​</a></h2><ul><li><strong>fixed</strong> an issue with the implementation of <code>elements</code> <a href="https://github.com/PoisotLab/SpeciesDistributionToolkit.jl/issues/422" target="_blank" rel="noreferrer">#422</a></li></ul><h2 id="v1.0.1" tabindex="-1"><code>v1.0.1</code> <a class="header-anchor" href="#v1.0.1" aria-label="Permalink to &quot;`v1.0.1` {#v1.0.1}&quot;">​</a></h2><ul><li><strong>removed</strong> specific occurrences used in tests that are no longer relevant/archived</li></ul><h2 id="v1.0.0" tabindex="-1"><code>v1.0.0</code> <a class="header-anchor" href="#v1.0.0" aria-label="Permalink to &quot;`v1.0.0` {#v1.0.0}&quot;">​</a></h2><ul><li><strong>added</strong> support for <code>OccurrencesInterface</code> at version 1</li></ul>',15)])])}const u=o(n,[["render",i]]);export{g as __pageData,u as default};
